"use client";

import { useForm } from "react-hook-form";
import { useState } from "react";
import { submitOnboardingResponse } from "@/app/actions/client-onboarding";
import { OnboardingQuestion } from "@/lib/validations/onboarding-form";

export function ClientOnboardingForm({ form: dbForm }: { form: any }) {
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [error, setError] = useState<string | null>(null);

    const questions = dbForm?.questions
        // eslint-disable-next-line @typescript-eslint/no-explicit-any
        ? (dbForm.questions as any[])
        : []; // Added a default empty array if dbForm or questions is undefined

    const form = useForm();

    async function onSubmit(data: any) {
        setIsSubmitting(true);
        setError(null);

        try {
            // Map react-hook-form flat structure to answers array
            const answers = questions.map((q) => {
                let answer = data[q.id];
                // Ensure defaults for specific types
                if (answer === undefined || answer === null) {
                    answer = q.type === "boolean" ? false : "";
                }

                // If boolean came through as string (radio button), fix typed value
                if (q.type === "boolean" && typeof answer === "string") {
                    answer = answer === "true";
                }

                return {
                    questionId: q.id,
                    answer: answer
                };
            });

            await submitOnboardingResponse({
                formId: dbForm.id,
                answers
            });
            // The action will automatically redirect to dashboard
        } catch (err: unknown) {
            setError(err instanceof Error ? err.message : "Failed to submit answers");
            setIsSubmitting(false);
        }
    }

    return (
        <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-8">
            {error && (
                <div className="rounded-md bg-red-50 p-4 text-sm text-red-600 dark:bg-red-900/20 dark:text-red-400">
                    {error}
                </div>
            )}

            <div className="space-y-6 rounded-2xl border border-zinc-200 bg-white p-6 shadow-sm dark:border-zinc-800 dark:bg-[#121215]">
                {questions.map((q) => (
                    <div key={q.id} className="border-b border-zinc-100 pb-6 last:border-0 last:pb-0 dark:border-zinc-800">
                        <label className="mb-2 block text-sm font-medium text-zinc-900 dark:text-zinc-100">
                            {q.label}
                            {q.required && <span className="ml-1 text-red-500">*</span>}
                        </label>

                        {q.type === "shortText" && (
                            <input
                                {...form.register(q.id, { required: q.required ? "This is required" : false })}
                                type="text"
                                className="w-full rounded-md border border-zinc-300 px-3 py-2 text-sm focus:border-zinc-500 focus:outline-none focus:ring-1 focus:ring-zinc-500 dark:border-zinc-700 dark:bg-[#09090b] dark:text-zinc-100"
                            />
                        )}

                        {q.type === "longText" && (
                            <textarea
                                {...form.register(q.id, { required: q.required ? "This is required" : false })}
                                rows={4}
                                className="w-full rounded-md border border-zinc-300 px-3 py-2 text-sm focus:border-zinc-500 focus:outline-none focus:ring-1 focus:ring-zinc-500 dark:border-zinc-700 dark:bg-[#09090b] dark:text-zinc-100"
                            />
                        )}

                        {q.type === "number" && (
                            <input
                                {...form.register(q.id, {
                                    required: q.required ? "This is required" : false,
                                    valueAsNumber: true
                                })}
                                type="number"
                                className="w-full rounded-md border border-zinc-300 px-3 py-2 text-sm focus:border-zinc-500 focus:outline-none focus:ring-1 focus:ring-zinc-500 dark:border-zinc-700 dark:bg-[#09090b] dark:text-zinc-100"
                            />
                        )}

                        {q.type === "boolean" && (
                            <div className="flex gap-4">
                                <label className="flex items-center gap-2 text-sm text-zinc-700 dark:text-zinc-300">
                                    <input
                                        {...form.register(q.id, { required: q.required ? "This is required" : false })}
                                        type="radio"
                                        value="true"
                                        className="text-zinc-900 focus:ring-zinc-500 dark:bg-[#09090b]"
                                    />
                                    Yes
                                </label>
                                <label className="flex items-center gap-2 text-sm text-zinc-700 dark:text-zinc-300">
                                    <input
                                        {...form.register(q.id, { required: q.required ? "This is required" : false })}
                                        type="radio"
                                        value="false"
                                        className="text-zinc-900 focus:ring-zinc-500 dark:bg-[#09090b]"
                                    />
                                    No
                                </label>
                            </div>
                        )}

                        {q.type === "multipleChoice" && q.options && (
                            <div className="space-y-2">
                                {q.options.map((opt: string, i: number) => (
                                    <label key={i} className="flex items-center gap-2 text-sm text-zinc-700 dark:text-zinc-300">
                                        <input
                                            {...form.register(q.id, { required: q.required ? "This is required" : false })}
                                            type="radio"
                                            value={opt}
                                            className="text-zinc-900 focus:ring-zinc-500 dark:bg-[#09090b]"
                                        />
                                        {opt}
                                    </label>
                                ))}
                            </div>
                        )}

                        {form.formState.errors[q.id] && (
                            <p className="mt-1 text-xs text-red-600">
                                {form.formState.errors[q.id]?.message as string}
                            </p>
                        )}
                    </div>
                ))}
            </div>

            <button
                type="submit"
                disabled={isSubmitting}
                className="w-full rounded-lg bg-zinc-900 px-4 py-3 text-sm font-semibold text-white transition hover:bg-zinc-700 disabled:opacity-50 dark:bg-zinc-100 dark:text-zinc-900 dark:hover:bg-zinc-300"
            >
                {isSubmitting ? "Submitting..." : "Complete Onboarding"}
            </button>
        </form>
    );
}

"use client";

import { useForm, useFieldArray } from "react-hook-form";
import { useState } from "react";
import { upsertMyOnboardingForm } from "@/app/actions/onboarding-forms";
import { upsertOnboardingFormSchema } from "@/lib/validations/onboarding-form";

// eslint-disable-next-line @typescript-eslint/no-explicit-any
function Trash2Icon(props: any) { return <svg {...props} xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M3 6h18" /><path d="M19 6v14c0 1-1 2-2 2H7c-1 0-2-1-2-2V6" /><path d="M8 6V4c0-1 1-2 2-2h4c1 0 2 1 2 2v2" /><line x1="10" x2="10" y1="11" y2="17" /><line x1="14" x2="14" y1="11" y2="17" /></svg>; }
// eslint-disable-next-line @typescript-eslint/no-explicit-any
function ArrowUpIcon(props: any) { return <svg {...props} xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m18 15-6-6-6 6" /></svg>; }
// eslint-disable-next-line @typescript-eslint/no-explicit-any
function ArrowDownIcon(props: any) { return <svg {...props} xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="m6 9 6 6 6-6" /></svg>; }
// eslint-disable-next-line @typescript-eslint/no-explicit-any
function PlusIcon(props: any) { return <svg {...props} xmlns="http://www.w3.org/2000/svg" width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round"><path d="M5 12h14" /><path d="M12 5v14" /></svg>; }

// For generating random IDs for new questions
function generateId() {
    return Math.random().toString(36).substring(2, 9);
}

export function OnboardingEditor({ initialData }: { initialData: any }) {
    const [isSubmitting, setIsSubmitting] = useState(false);
    const [message, setMessage] = useState<{ type: "success" | "error"; text: string } | null>(null);

    // Parse options from string array to comma-separated string for editing
    // eslint-disable-next-line @typescript-eslint/no-explicit-any
    const defaultQuestions = Array.isArray(initialData?.questions)
        ? (initialData.questions as any[]).map((q: any) => ({
            ...q,
            optionsString: Array.isArray(q.options) ? q.options.join(", ") : ""
        }))
        : [];

    const form = useForm({
        defaultValues: {
            isActive: initialData?.isActive ?? true,
            questions: defaultQuestions,
        },
    });

    const { fields, append, remove, move } = useFieldArray({
        control: form.control,
        name: "questions",
    });

    async function onSubmit(rawValues: any) {
        setIsSubmitting(true);
        setMessage(null);

        try {
            // Transform optionString back to options array
            // eslint-disable-next-line @typescript-eslint/no-explicit-any
            const transformedQuestions = rawValues.questions.map((q: any) => {
                const base = {
                    id: q.id,
                    type: q.type,
                    label: q.label,
                    required: q.required,
                };

                if (q.type === "multipleChoice" && q.optionsString) {
                    return {
                        ...base,
                        options: q.optionsString.split(",").map((s: string) => s.trim()).filter(Boolean)
                    };
                }

                return base;
            });

            // Re-validate against the strict zod schema
            const validated = upsertOnboardingFormSchema.parse({
                isActive: rawValues.isActive,
                questions: transformedQuestions
            });

            await upsertMyOnboardingForm(validated);

            setMessage({ type: "success", text: "Questionnaire saved successfully." });
        } catch (err: unknown) {
            setMessage({ type: "error", text: err instanceof Error ? err.message : "Failed to save questionnaire." });
        } finally {
            setIsSubmitting(false);
        }
    }

    return (
        <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-6">
            {message?.type === "error" && (
                <div className="rounded-md bg-red-50 p-4 text-sm text-red-600 dark:bg-red-900/20 dark:text-red-400">
                    {message.text}
                </div>
            )}
            {message?.type === "success" && (
                <div className="rounded-md bg-green-50 p-4 text-sm text-green-600 dark:bg-green-900/20 dark:text-green-400">
                    {message.text}
                </div>
            )}

            <div className="flex items-center gap-3 py-2 border-b border-zinc-200 dark:border-zinc-800 pb-4">
                <input
                    {...form.register("isActive")}
                    id="isActive"
                    type="checkbox"
                    className="rounded border-zinc-300 text-zinc-900 focus:ring-zinc-500 dark:border-zinc-700 dark:bg-[#09090b]"
                />
                <label htmlFor="isActive" className="text-sm font-medium text-zinc-700 dark:text-zinc-300">
                    Require new clients to complete this intake questionnaire
                </label>
            </div>

            <div className="space-y-4">
                {fields.length === 0 ? (
                    <div className="rounded-xl border border-dashed border-zinc-200 p-8 text-center dark:border-zinc-800">
                        <p className="text-sm text-zinc-500 dark:text-zinc-400">No questions added yet.</p>
                    </div>
                ) : (
                    fields.map((field, index) => {
                        const type = form.watch(`questions.${index}.type`);
                        return (
                            <div key={field.id} className="rounded-xl border border-zinc-200 bg-white p-5 shadow-sm dark:border-zinc-800 dark:bg-[#121215]">

                                {/* Hidden input to track generated ID logic across reorders without conflicts */}
                                <input type="hidden" {...form.register(`questions.${index}.id`)} />

                                <div className="flex items-start justify-between gap-4">
                                    <div className="flex-1 space-y-4">

                                        <div className="flex flex-col sm:flex-row gap-4">
                                            <div className="flex-1">
                                                <label className="mb-1 block text-xs font-medium text-zinc-500 dark:text-zinc-400">
                                                    Question Text
                                                </label>
                                                <input
                                                    {...form.register(`questions.${index}.label`)}
                                                    placeholder="e.g. What are your primary fitness goals?"
                                                    className="w-full rounded-md border border-zinc-300 px-3 py-2 text-sm focus:border-zinc-500 focus:outline-none focus:ring-1 focus:ring-zinc-500 dark:border-zinc-700 dark:bg-[#09090b] dark:text-zinc-100"
                                                />
                                            </div>

                                            <div className="w-full sm:w-48">
                                                <label className="mb-1 block text-xs font-medium text-zinc-500 dark:text-zinc-400">
                                                    Type
                                                </label>
                                                <select
                                                    {...form.register(`questions.${index}.type`)}
                                                    className="w-full rounded-md border border-zinc-300 px-3 py-2 text-sm focus:border-zinc-500 focus:outline-none focus:ring-1 focus:ring-zinc-500 dark:border-zinc-700 dark:bg-[#09090b] dark:text-zinc-100"
                                                >
                                                    <option value="shortText">Short Text</option>
                                                    <option value="longText">Long Text</option>
                                                    <option value="number">Number</option>
                                                    <option value="multipleChoice">Multiple Choice</option>
                                                    <option value="boolean">Yes / No</option>
                                                </select>
                                            </div>
                                        </div>

                                        {type === "multipleChoice" && (
                                            <div>
                                                <label className="mb-1 block text-xs font-medium text-zinc-500 dark:text-zinc-400">
                                                    Options (comma separated)
                                                </label>
                                                <input
                                                    {...form.register(`questions.${index}.optionsString`)}
                                                    placeholder="Option A, Option B, Option C"
                                                    className="w-full rounded-md border border-zinc-300 px-3 py-2 text-sm focus:border-zinc-500 focus:outline-none focus:ring-1 focus:ring-zinc-500 dark:border-zinc-700 dark:bg-[#09090b] dark:text-zinc-100"
                                                />
                                            </div>
                                        )}

                                        <div className="flex items-center gap-2">
                                            <input
                                                {...form.register(`questions.${index}.required`)}
                                                type="checkbox"
                                                id={`req-${field.id}`}
                                                className="rounded border-zinc-300 text-zinc-900 focus:ring-zinc-500 dark:border-zinc-700 dark:bg-[#09090b]"
                                            />
                                            <label htmlFor={`req-${field.id}`} className="text-xs font-medium text-zinc-600 dark:text-zinc-400">
                                                Required Question
                                            </label>
                                        </div>

                                    </div>

                                    <div className="flex shrink-0 flex-col items-center gap-1">
                                        <button
                                            type="button"
                                            onClick={() => move(index, index - 1)}
                                            disabled={index === 0}
                                            className="rounded p-1.5 text-zinc-400 hover:bg-zinc-100 hover:text-zinc-900 disabled:opacity-30 dark:hover:bg-zinc-800 dark:hover:text-zinc-100"
                                        >
                                            <ArrowUpIcon className="h-4 w-4" />
                                        </button>
                                        <button
                                            type="button"
                                            onClick={() => remove(index)}
                                            className="rounded p-1.5 text-zinc-400 hover:bg-red-50 hover:text-red-600 dark:hover:bg-red-900/20 dark:hover:text-red-400"
                                        >
                                            <Trash2Icon className="h-4 w-4" />
                                        </button>
                                        <button
                                            type="button"
                                            onClick={() => move(index, index + 1)}
                                            disabled={index === fields.length - 1}
                                            className="rounded p-1.5 text-zinc-400 hover:bg-zinc-100 hover:text-zinc-900 disabled:opacity-30 dark:hover:bg-zinc-800 dark:hover:text-zinc-100"
                                        >
                                            <ArrowDownIcon className="h-4 w-4" />
                                        </button>
                                    </div>
                                </div>
                            </div>
                        );
                    })
                )}
            </div>

            <button
                type="button"
                onClick={() => append({ id: generateId(), type: "shortText", label: "", required: false, optionsString: "" })}
                className="flex w-full items-center justify-center gap-2 rounded-xl border border-dashed border-zinc-300 bg-zinc-50 py-4 text-sm font-medium text-zinc-600 transition hover:border-zinc-400 hover:bg-zinc-100 dark:border-zinc-700 dark:bg-[#121215]/50 dark:text-zinc-400 dark:hover:border-zinc-600 dark:hover:bg-[#121215]"
            >
                <PlusIcon className="h-4 w-4" />
                Add Question
            </button>

            <div className="pt-6 border-t border-zinc-200 dark:border-zinc-800 flex justify-end">
                <button
                    type="submit"
                    disabled={isSubmitting}
                    className="rounded-lg bg-zinc-900 px-6 py-2.5 text-sm font-semibold text-white transition hover:bg-zinc-700 disabled:opacity-50 dark:bg-zinc-100 dark:text-zinc-900 dark:hover:bg-zinc-300"
                >
                    {isSubmitting ? "Saving..." : "Save Questionnaire"}
                </button>
            </div>
        </form>
    );
}

"use client";

import { useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";
import { TrainingDayCard } from "./training-day-card";
import {
  saveTrainingProgram,
  publishTrainingProgram,
} from "@/app/actions/training-programs";
import type { TrainingDayGroup, TrainingBlock, BlockType } from "@/types/training";

type TemplateOption = {
  id: string;
  name: string;
  days: {
    dayName: string;
    blocks: { type: BlockType; title: string; content: string }[];
  }[];
};

type InitialProgram = {
  id: string;
  status: "DRAFT" | "PUBLISHED";
  templateSourceId: string | null;
  weeklyFrequency: number | null;
  clientNotes: string | null;
  injuries: string | null;
  equipment: string | null;
  days: {
    dayName: string;
    blocks: { type: BlockType; title: string; content: string }[];
  }[];
} | null;

type Mode = "empty" | "assign" | "edit";
type ViewMode = "editor" | "preview";

const BLOCK_TYPE_LABELS: Record<BlockType, string> = {
  EXERCISE: "Exercise",
  ACTIVATION: "Activation",
  INSTRUCTION: "Instruction",
  SUPERSET: "Superset",
  CARDIO: "Cardio",
  OPTIONAL: "Optional",
};

const BLOCK_TYPE_BADGE: Record<BlockType, string> = {
  EXERCISE: "",
  ACTIVATION: "bg-yellow-50 text-yellow-700 dark:bg-yellow-900/30 dark:text-yellow-300",
  INSTRUCTION: "bg-zinc-100 text-zinc-600 dark:bg-zinc-800 dark:text-zinc-300",
  SUPERSET: "bg-purple-50 text-purple-700 dark:bg-purple-900/30 dark:text-purple-300",
  CARDIO: "bg-green-50 text-green-700 dark:bg-green-900/30 dark:text-green-300",
  OPTIONAL: "bg-zinc-50 text-zinc-500 dark:bg-zinc-800/60 dark:text-zinc-400",
};

function ProgramPreview({
  days,
  weeklyFrequency,
  clientNotes,
}: {
  days: TrainingDayGroup[];
  weeklyFrequency: string;
  clientNotes: string;
}) {
  return (
    <div className="space-y-3">
      {(weeklyFrequency || clientNotes) && (
        <div className="rounded-xl border border-zinc-200/80 bg-white px-4 py-3 dark:border-zinc-800/80 dark:bg-[#121215]">
          {weeklyFrequency && (
            <p className="text-sm">
              <span className="font-semibold">{weeklyFrequency}×</span>{" "}
              <span className="text-zinc-500">per week</span>
            </p>
          )}
          {clientNotes && (
            <p className="mt-1 text-sm text-zinc-500">{clientNotes}</p>
          )}
        </div>
      )}
      {days.map((day, i) => (
        <div
          key={i}
          className="overflow-hidden rounded-xl border border-zinc-200/80 bg-white dark:border-zinc-800/80 dark:bg-[#121215]"
        >
          <div className="border-b border-zinc-100 px-4 py-3 dark:border-zinc-800">
            <h3 className="text-sm font-semibold">{day.dayName || `Day ${i + 1}`}</h3>
          </div>
          {day.blocks.length === 0 ? (
            <p className="px-4 py-3 text-sm text-zinc-400">No blocks yet.</p>
          ) : (
            <div className="divide-y divide-zinc-100/80 dark:divide-zinc-800/60">
              {day.blocks.map((block, j) => (
                <div key={j} className="px-4 py-3">
                  <div className="flex items-baseline gap-2">
                    {block.type !== "EXERCISE" && (
                      <span
                        className={`shrink-0 rounded-full px-2 py-0.5 text-[10px] font-semibold ${BLOCK_TYPE_BADGE[block.type]}`}
                      >
                        {BLOCK_TYPE_LABELS[block.type]}
                      </span>
                    )}
                    {block.title && (
                      <span className="text-sm font-medium">{block.title}</span>
                    )}
                  </div>
                  {block.content && (
                    <p className="mt-1 whitespace-pre-wrap text-sm leading-relaxed text-zinc-600 dark:text-zinc-400">
                      {block.content}
                    </p>
                  )}
                </div>
              ))}
            </div>
          )}
        </div>
      ))}
      {days.length === 0 && (
        <p className="py-6 text-center text-sm text-zinc-400">No training days added yet.</p>
      )}
    </div>
  );
}

export function TrainingProgramEditor({
  clientId,
  weekStartDate,
  initialProgram,
  templates = [],
}: {
  clientId: string;
  weekStartDate: string;
  initialProgram: InitialProgram;
  templates?: TemplateOption[];
}) {
  const router = useRouter();

  const [mode, setMode] = useState<Mode>(initialProgram ? "edit" : "empty");
  const [viewMode, setViewMode] = useState<ViewMode>("editor");
  const [programId, setProgramId] = useState<string | null>(initialProgram?.id ?? null);
  const [status, setStatus] = useState<"DRAFT" | "PUBLISHED" | null>(
    initialProgram?.status ?? null
  );
  const [days, setDays] = useState<TrainingDayGroup[]>(
    initialProgram?.days.map((d) => ({
      dayName: d.dayName,
      blocks: d.blocks.map((b) => ({
        type: b.type,
        title: b.title,
        content: b.content,
      })),
    })) ?? []
  );

  // Assignment form fields
  const [selectedTemplateId, setSelectedTemplateId] = useState(
    initialProgram?.templateSourceId ?? ""
  );
  const [weeklyFrequency, setWeeklyFrequency] = useState(
    initialProgram?.weeklyFrequency?.toString() ?? ""
  );
  const [injuries, setInjuries] = useState(initialProgram?.injuries ?? "");
  const [equipment, setEquipment] = useState(initialProgram?.equipment ?? "");
  const [clientNotes, setClientNotes] = useState(initialProgram?.clientNotes ?? "");

  const [saving, setSaving] = useState(false);
  const [publishing, setPublishing] = useState(false);
  const [error, setError] = useState<string | null>(null);

  const activeTemplateName =
    templates.find((t) => t.id === (selectedTemplateId || initialProgram?.templateSourceId))
      ?.name ?? null;

  function addDay() {
    setDays((prev) => [...prev, { dayName: "", blocks: [] }]);
  }

  function removeDay(index: number) {
    setDays((prev) => prev.filter((_, i) => i !== index));
  }

  function updateDay(index: number, updated: TrainingDayGroup) {
    setDays((prev) => prev.map((d, i) => (i === index ? updated : d)));
  }

  function buildPayload(overrideDays?: TrainingDayGroup[]) {
    return {
      clientId,
      weekStartDate,
      days: overrideDays ?? days,
      weeklyFrequency: weeklyFrequency ? Number(weeklyFrequency) : undefined,
      clientNotes: clientNotes || undefined,
      injuries: injuries || undefined,
      equipment: equipment || undefined,
      templateSourceId: selectedTemplateId || undefined,
    };
  }

  function getTemplateDays(templateId: string): TrainingDayGroup[] {
    const tpl = templates.find((t) => t.id === templateId);
    if (!tpl) return [];
    return tpl.days.map((d) => ({
      dayName: d.dayName,
      blocks: d.blocks.map((b) => ({
        type: b.type as BlockType,
        title: b.title,
        content: b.content,
      })),
    }));
  }

  async function handleSave() {
    setSaving(true);
    setError(null);
    try {
      let payloadDays = days;
      if (mode === "assign" && selectedTemplateId) {
        payloadDays = getTemplateDays(selectedTemplateId);
        setDays(payloadDays);
      }

      const result = await saveTrainingProgram(buildPayload(payloadDays));
      if ("error" in result) {
        setError("Save failed — check your inputs.");
      } else {
        setProgramId(result.programId);
        setStatus("DRAFT");
        setMode("edit");
        router.refresh();
      }
    } catch {
      setError("Save failed. Please try again.");
    } finally {
      setSaving(false);
    }
  }

  async function handlePublish() {
    setPublishing(true);
    setError(null);
    try {
      let payloadDays = days;
      if (mode === "assign" && selectedTemplateId) {
        payloadDays = getTemplateDays(selectedTemplateId);
        setDays(payloadDays);
      }

      let id = programId;
      if (!id) {
        const result = await saveTrainingProgram(buildPayload(payloadDays));
        if ("error" in result) {
          setError("Failed to save before publishing.");
          setPublishing(false);
          return;
        }
        id = result.programId;
        setProgramId(id);
      }
      await publishTrainingProgram({ programId: id });
      setStatus("PUBLISHED");
      setMode("edit");
      router.refresh();
    } catch {
      setError("Publish failed. Please try again.");
    } finally {
      setPublishing(false);
    }
  }

  // ── Empty state ──────────────────────────────────────────────────────────
  if (mode === "empty") {
    return (
      <div className="rounded-2xl border border-zinc-200/80 bg-white dark:border-zinc-800/80 dark:bg-[#121215]">
        <div className="border-b border-zinc-100 px-5 py-4 dark:border-zinc-800">
          <h2 className="text-sm font-semibold">Training Plan</h2>
          <p className="mt-0.5 text-xs text-zinc-400">No training plan assigned yet</p>
        </div>
        <div className="px-5 py-6 space-y-3">
          <button
            type="button"
            onClick={() => setMode(templates.length > 0 ? "assign" : "edit")}
            className="w-full rounded-xl bg-zinc-900 py-3.5 text-sm font-semibold text-white transition-colors hover:bg-zinc-700 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-500 dark:bg-zinc-100 dark:text-zinc-900 dark:hover:bg-zinc-300"
          >
            {templates.length > 0 ? "Assign from Template" : "Create Training Plan"}
          </button>
          {templates.length > 0 && (
            <div className="flex gap-2">
              <button
                type="button"
                onClick={() => { setDays([]); setMode("edit"); }}
                className="flex-1 rounded-xl border border-zinc-200 py-2.5 text-sm font-semibold text-zinc-600 transition-colors hover:bg-zinc-50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-500 dark:border-zinc-700 dark:text-zinc-400 dark:hover:bg-zinc-800"
              >
                Custom Plan
              </button>
              <Link
                href={`/coach/clients/${clientId}/import-training`}
                className="flex-1 rounded-xl border border-zinc-200 py-2.5 text-center text-sm font-semibold text-zinc-600 transition-colors hover:bg-zinc-50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-500 dark:border-zinc-700 dark:text-zinc-400 dark:hover:bg-zinc-800"
              >
                Import
              </Link>
            </div>
          )}
        </div>
      </div>
    );
  }

  // ── Assign state ─────────────────────────────────────────────────────────
  if (mode === "assign") {
    return (
      <div className="space-y-4">
        <div className="flex items-center gap-3">
          <button
            type="button"
            onClick={() => setMode(programId ? "edit" : "empty")}
            className="flex h-8 w-8 items-center justify-center rounded-lg text-zinc-400 transition-colors hover:bg-zinc-100 hover:text-zinc-600 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-500 dark:hover:bg-zinc-800 dark:hover:text-zinc-300"
            aria-label="Back"
          >
            &larr;
          </button>
          <h2 className="text-sm font-semibold">Assign Training Plan</h2>
        </div>

        <div className="rounded-2xl border border-zinc-200/80 bg-white dark:border-zinc-800/80 dark:bg-[#121215]">
          {/* Template picker — card list */}
          <div className="border-b border-zinc-100 dark:border-zinc-800">
            <p className="px-5 pt-4 pb-2 text-xs font-semibold text-zinc-500">
              Choose a template
            </p>
            {templates.length === 0 ? (
              <p className="px-5 pb-4 text-sm text-zinc-400">
                No templates yet.{" "}
                <Link
                  href="/coach/templates"
                  className="font-semibold text-zinc-700 underline underline-offset-2 dark:text-zinc-300"
                >
                  Create one
                </Link>{" "}
                first.
              </p>
            ) : (
              <div className="divide-y divide-zinc-100/80 dark:divide-zinc-800/60">
                {templates.map((t) => {
                  const isSelected = selectedTemplateId === t.id;
                  return (
                    <button
                      key={t.id}
                      type="button"
                      onClick={() => setSelectedTemplateId(t.id)}
                      aria-pressed={isSelected}
                      className={`w-full px-5 py-3.5 text-left transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-inset focus-visible:ring-zinc-500 ${
                        isSelected
                          ? "bg-zinc-50 dark:bg-zinc-900/50"
                          : "hover:bg-zinc-50/60 dark:hover:bg-zinc-900/30"
                      }`}
                    >
                      <div className="flex items-center justify-between gap-3">
                        <span className="truncate text-sm font-semibold">{t.name}</span>
                        <div className="flex shrink-0 items-center gap-2">
                          <span className="text-xs text-zinc-400">
                            {t.days.length} {t.days.length === 1 ? "day" : "days"}
                          </span>
                          {isSelected && (
                            <span className="text-xs font-semibold text-emerald-600 dark:text-emerald-400">
                              ✓
                            </span>
                          )}
                        </div>
                      </div>
                    </button>
                  );
                })}
              </div>
            )}
          </div>

          {/* Client adjustments — only shown once a template is selected */}
          {selectedTemplateId && (
            <div className="px-5 py-4">
              <p className="mb-3 text-xs font-semibold uppercase tracking-wide text-zinc-400">
                Client adjustments{" "}
                <span className="font-normal normal-case">(optional)</span>
              </p>
              <div className="grid gap-3 sm:grid-cols-2">
                <div className="flex flex-col gap-1.5">
                  <label htmlFor="assign-frequency" className="text-xs font-semibold text-zinc-500">
                    Days per week
                  </label>
                  <input
                    id="assign-frequency"
                    type="number"
                    min={1}
                    max={7}
                    value={weeklyFrequency}
                    onChange={(e) => setWeeklyFrequency(e.target.value)}
                    placeholder="e.g. 4"
                    className="rounded-lg border border-zinc-200 bg-transparent px-3 py-2 text-sm placeholder-zinc-400 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-500 dark:border-zinc-700"
                  />
                </div>
                <div className="flex flex-col gap-1.5">
                  <label htmlFor="assign-injuries" className="text-xs font-semibold text-zinc-500">
                    Injuries / limitations
                  </label>
                  <input
                    id="assign-injuries"
                    type="text"
                    value={injuries}
                    onChange={(e) => setInjuries(e.target.value)}
                    placeholder="e.g. right shoulder"
                    className="rounded-lg border border-zinc-200 bg-transparent px-3 py-2 text-sm placeholder-zinc-400 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-500 dark:border-zinc-700"
                  />
                </div>
                <div className="flex flex-col gap-1.5">
                  <label htmlFor="assign-equipment" className="text-xs font-semibold text-zinc-500">
                    Equipment
                  </label>
                  <input
                    id="assign-equipment"
                    type="text"
                    value={equipment}
                    onChange={(e) => setEquipment(e.target.value)}
                    placeholder="e.g. full gym, home dumbbells"
                    className="rounded-lg border border-zinc-200 bg-transparent px-3 py-2 text-sm placeholder-zinc-400 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-500 dark:border-zinc-700"
                  />
                </div>
                <div className="flex flex-col gap-1.5">
                  <label htmlFor="assign-notes" className="text-xs font-semibold text-zinc-500">
                    Client notes
                  </label>
                  <input
                    id="assign-notes"
                    type="text"
                    value={clientNotes}
                    onChange={(e) => setClientNotes(e.target.value)}
                    placeholder="Anything the client should know"
                    className="rounded-lg border border-zinc-200 bg-transparent px-3 py-2 text-sm placeholder-zinc-400 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-500 dark:border-zinc-700"
                  />
                </div>
              </div>
            </div>
          )}
        </div>

        {error && (
          <p className="text-xs font-medium text-red-500" role="alert">
            {error}
          </p>
        )}

        <div className="flex gap-3">
          <button
            type="button"
            onClick={handleSave}
            disabled={!selectedTemplateId || saving || publishing}
            className="flex-1 rounded-xl border border-zinc-200 py-3 text-sm font-semibold text-zinc-700 transition-colors hover:bg-zinc-50 disabled:cursor-not-allowed disabled:opacity-40 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-500 dark:border-zinc-700 dark:text-zinc-300 dark:hover:bg-zinc-800"
          >
            {saving ? "Saving…" : "Save as Draft"}
          </button>
          <button
            type="button"
            onClick={handlePublish}
            disabled={!selectedTemplateId || saving || publishing}
            className="flex-1 rounded-xl bg-zinc-900 py-3 text-sm font-semibold text-white transition-colors hover:bg-zinc-700 disabled:cursor-not-allowed disabled:opacity-40 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-500 dark:bg-zinc-100 dark:text-zinc-900 dark:hover:bg-zinc-300"
          >
            {publishing ? "Publishing…" : "Assign & Publish"}
          </button>
        </div>
      </div>
    );
  }

  // ── Edit state ───────────────────────────────────────────────────────────
  return (
    <div className="space-y-4">
      {/* Header */}
      <div className="flex items-center justify-between">
        <div className="flex items-center gap-2.5">
          <h2 className="text-sm font-semibold">Training Plan</h2>
          {status && (
            <span
              aria-live="polite"
              className={`rounded-full px-2 py-0.5 text-[11px] font-semibold ${
                status === "PUBLISHED"
                  ? "bg-emerald-500/10 text-emerald-600 dark:bg-emerald-500/20 dark:text-emerald-400"
                  : "bg-amber-500/10 text-amber-600 dark:bg-amber-500/20 dark:text-amber-400"
              }`}
            >
              {status === "PUBLISHED" ? "Published" : "Draft"}
            </span>
          )}
          {activeTemplateName && (
            <span className="hidden text-xs text-zinc-400 sm:inline">{activeTemplateName}</span>
          )}
        </div>
        <div className="flex items-center gap-2">
          {/* Editor / Preview toggle */}
          <div className="flex rounded-lg border border-zinc-200 p-0.5 text-xs dark:border-zinc-700">
            <button
              type="button"
              onClick={() => setViewMode("editor")}
              className={`rounded-md px-2.5 py-1 font-semibold transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-500 ${
                viewMode === "editor"
                  ? "bg-zinc-900 text-white dark:bg-zinc-100 dark:text-zinc-900"
                  : "text-zinc-500 hover:text-zinc-700 dark:hover:text-zinc-300"
              }`}
            >
              Editor
            </button>
            <button
              type="button"
              onClick={() => setViewMode("preview")}
              className={`rounded-md px-2.5 py-1 font-semibold transition-colors focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-500 ${
                viewMode === "preview"
                  ? "bg-zinc-900 text-white dark:bg-zinc-100 dark:text-zinc-900"
                  : "text-zinc-500 hover:text-zinc-700 dark:hover:text-zinc-300"
              }`}
            >
              Preview
            </button>
          </div>
          {templates.length > 0 && (
            <button
              type="button"
              onClick={() => setMode("assign")}
              className="rounded-lg px-3 py-2 text-xs font-semibold text-zinc-500 transition-colors hover:bg-zinc-100 hover:text-zinc-700 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-500 dark:hover:bg-zinc-800 dark:hover:text-zinc-300"
            >
              Change Template
            </button>
          )}
        </div>
      </div>

      {/* Preview mode */}
      {viewMode === "preview" ? (
        <ProgramPreview
          days={days}
          weeklyFrequency={weeklyFrequency}
          clientNotes={clientNotes}
        />
      ) : (
        /* Editor mode */
        <div className="rounded-2xl border border-zinc-200/80 bg-white dark:border-zinc-800/80 dark:bg-[#121215]">
          <div className="flex items-center justify-between border-b border-zinc-100 px-5 py-3 dark:border-zinc-800">
            <h3 className="text-xs font-semibold uppercase tracking-wide text-zinc-500">
              Training Days
            </h3>
            <button
              type="button"
              onClick={addDay}
              className="rounded-lg px-3 py-2 text-xs font-semibold text-zinc-500 transition-colors hover:bg-zinc-100 hover:text-zinc-700 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-500 dark:hover:bg-zinc-800 dark:hover:text-zinc-300"
            >
              + Add Day
            </button>
          </div>

          <div className="divide-y divide-zinc-100/80 dark:divide-zinc-800/60">
            {days.length === 0 ? (
              <div className="px-5 py-12 text-center">
                <p className="text-sm text-zinc-400">No training days yet.</p>
                <button
                  type="button"
                  onClick={addDay}
                  className="mt-3 text-sm font-semibold text-zinc-900 underline underline-offset-2 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-500 dark:text-zinc-100"
                >
                  Add a day to start
                </button>
              </div>
            ) : (
              days.map((day, i) => (
                <TrainingDayCard
                  key={i}
                  day={day}
                  index={i}
                  onChange={(updated) => updateDay(i, updated)}
                  onRemove={() => removeDay(i)}
                />
              ))
            )}
          </div>
        </div>
      )}

      {/* Actions */}
      {error && (
        <p className="text-xs font-medium text-red-500" role="alert">
          {error}
        </p>
      )}
      <div className="flex gap-3">
        <button
          type="button"
          onClick={handleSave}
          disabled={saving || publishing}
          className="flex-1 rounded-xl border border-zinc-200 py-3 text-sm font-semibold text-zinc-700 transition-colors hover:bg-zinc-50 disabled:cursor-not-allowed disabled:opacity-50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-500 dark:border-zinc-700 dark:text-zinc-300 dark:hover:bg-zinc-800"
        >
          {saving ? "Saving…" : "Save Draft"}
        </button>
        <button
          type="button"
          onClick={handlePublish}
          disabled={saving || publishing}
          className="flex-1 rounded-xl bg-zinc-900 py-3 text-sm font-semibold text-white transition-colors hover:bg-zinc-700 disabled:cursor-not-allowed disabled:opacity-50 focus-visible:outline-none focus-visible:ring-2 focus-visible:ring-zinc-500 dark:bg-zinc-100 dark:text-zinc-900 dark:hover:bg-zinc-300"
        >
          {publishing ? "Publishing…" : status === "PUBLISHED" ? "Republish" : "Publish"}
        </button>
      </div>
    </div>
  );
}
